#include <stdio.h>
#include <stdlib.h>

int totalFruits(int *fruits, int n) {
    int left = 0, maxLen = 0, types = 0;
    int *cnt = (int *)calloc(100001, sizeof(int)); // fruit values ≤ 1e5
    for (int right = 0; right < n; ++right) {
        if (cnt[fruits[right]] == 0) types++;
        cnt[fruits[right]]++;
        while (types > 2) {
            cnt[fruits[left]]--;
            if (cnt[fruits[left]] == 0) types--;
            left++;
        }
        int cur = right - left + 1;
        if (cur > maxLen) maxLen = cur;
    }
    free(cnt);
    return maxLen;
}

int main() {
    int t; if (scanf("%d", &t) != 1) return 0;
    while (t--) {
        int n; scanf("%d", &n);
        int *fruits = (int *)malloc(n * sizeof(int));
        for (int i = 0; i < n; ++i) scanf("%d", &fruits[i]);
        printf("%d\n", totalFruits(fruits, n));
        free(fruits);
    }
    return 0;
}

