#include <bits/stdc++.h>
using namespace std;

int totalFruits(const vector<int>& fruits) {
    unordered_map<int,int> cnt;
    int left = 0, maxLen = 0;
    for (int right = 0; right < (int)fruits.size(); ++right) {
        cnt[fruits[right]]++;
        while (cnt.size() > 2) {
            int val = fruits[left];
            if (--cnt[val] == 0) cnt.erase(val);
            ++left;
        }
        maxLen = max(maxLen, right - left + 1);
    }
    return maxLen;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int t; if (!(cin >> t)) return 0;
    while (t--) {
        int n; cin >> n;
        vector<int> fruits(n);
        for (int i = 0; i < n; ++i) cin >> fruits[i];
        cout << totalFruits(fruits) << '\n';
    }
    return 0;
}

