import java.io.*;
import java.util.*;

public class Main {
    private static int totalFruits(int[] fruits) {
        Map<Integer, Integer> cnt = new HashMap<>();
        int left = 0, max = 0;
        for (int right = 0; right < fruits.length; ++right) {
            cnt.put(fruits[right], cnt.getOrDefault(fruits[right], 0) + 1);
            while (cnt.size() > 2) {
                int val = fruits[left];
                int newCnt = cnt.get(val) - 1;
                if (newCnt == 0) cnt.remove(val);
                else cnt.put(val, newCnt);
                left++;
            }
            max = Math.max(max, right - left + 1);
        }
        return max;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb = new StringBuilder();
        int t = Integer.parseInt(br.readLine().trim());
        while (t-- > 0) {
            int n = Integer.parseInt(br.readLine().trim());
            int[] fruits = new int[n];
            StringTokenizer st = new StringTokenizer(br.readLine());
            for (int i = 0; i < n; ++i) fruits[i] = Integer.parseInt(st.nextToken());
            sb.append(totalFruits(fruits)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

