let idx = 0;
const t = Number(input[idx++]);
let outputs = [];
for (let caseNum = 0; caseNum < t; caseNum++) {
  const n = Number(input[idx++]);
  const fruits = [];
  for (let i = 0; i < n; i++) fruits.push(Number(input[idx++]));
  const count = new Map();
  let left = 0, maxLen = 0;
  for (let right = 0; right < n; right++) {
    const val = fruits[right];
    count.set(val, (count.get(val) || 0) + 1);
    while (count.size > 2) {
      const lval = fruits[left];
      const newCnt = count.get(lval) - 1;
      if (newCnt === 0) count.delete(lval);
      else count.set(lval, newCnt);
      left++;
    }
    const cur = right - left + 1;
    if (cur > maxLen) maxLen = cur;
  }
  outputs.push(String(maxLen));
}
